import tarfile
import os


def extract_tar(tar_path: str, destination: str) -> None:
    """
    Safely extracts a tar file to a destination directory.
    
    Prevents path traversal attacks and ensures safe extraction.
    
    Args:
        tar_path: Path to the tar file to extract.
        destination: Directory where the tar file contents will be extracted.
    
    Raises:
        ValueError: If the tar file contains unsafe paths (path traversal).
        FileNotFoundError: If the tar file or destination doesn't exist.
        tarfile.TarError: If the file is not a valid tar archive.
    """
    # Resolve and validate paths to prevent path injection
    tar_path = os.path.realpath(tar_path)
    destination = os.path.realpath(destination)
    
    if not os.path.isfile(tar_path):
        raise FileNotFoundError(f"Tar file not found: {tar_path}")
    
    if not os.path.isdir(destination):
        raise FileNotFoundError(f"Destination directory not found: {destination}")
    
    with tarfile.open(tar_path, 'r:*') as tar:
        # Check all members for path traversal attacks before extracting
        for member in tar.getmembers():
            member_path = os.path.realpath(os.path.join(destination, member.name))
            
            # Ensure the extracted file stays within the destination directory
            if not member_path.startswith(destination + os.sep) and member_path != destination:
                raise ValueError(
                    f"Attempted path traversal in tar file: {member.name}"
                )
            
            # Reject absolute paths in member names
            if os.path.isabs(member.name):
                raise ValueError(
                    f"Tar file contains absolute path: {member.name}"
                )
            
            # Reject members with '..' components
            if '..' in member.name.split('/') or '..' in member.name.split(os.sep):
                raise ValueError(
                    f"Tar file contains path traversal component: {member.name}"
                )
            
            # Reject symbolic links that point outside the destination
            if member.issym() or member.islnk():
                link_target = member.linkname
                if os.path.isabs(link_target):
                    raise ValueError(
                        f"Tar file contains symlink with absolute target: {member.name} -> {link_target}"
                    )
                resolved_link = os.path.realpath(
                    os.path.join(destination, os.path.dirname(member.name), link_target)
                )
                if not resolved_link.startswith(destination + os.sep) and resolved_link != destination:
                    raise ValueError(
                        f"Tar file contains symlink pointing outside destination: "
                        f"{member.name} -> {link_target}"
                    )
        
        # Safe to extract all members
        tar.extractall(path=destination)


if __name__ == "__main__":
    import sys
    
    if len(sys.argv) != 3:
        print(f"Usage: {sys.argv[0]} <tar_file> <destination_directory>")
